"use client";

import React, { useState, useEffect } from "react";
import "./globals.css";

// Metadata is handled separately for SEO in Next.js Server Components, 
// but since this layout is 'use client' for theme logic, 
// we will manage the meta tags within the Head or through a separate approach.
// For now, let's keep it clean.

export default function RootLayout({ children }) {
  const [theme, setTheme] = useState("light");

  useEffect(() => {
    const savedTheme = localStorage.getItem("theme") || 
      (window.matchMedia("(prefers-color-scheme: dark)").matches ? "dark" : "light");
    setTheme(savedTheme);
  }, []);

  useEffect(() => {
    if (theme === "dark") {
      document.documentElement.classList.add("dark");
    } else {
      document.documentElement.classList.remove("dark");
    }
    localStorage.setItem("theme", theme);
  }, [theme]);

  return (
    <html lang="en">
      <head>
        <title>Mubxbot | School of Computing Directory</title>
        <meta name="description" content="Premium search tool for the School of Computing and Informatics doctors and staff." />
        <meta name="viewport" content="width=device-width, initial-scale=1, maximum-scale=1" />
        
        {/* Favicons & Branding Icons */}
        <link rel="icon" href="/favicon.ico" sizes="any" />
        <link rel="icon" href="/favicon-32x32.png" type="image/png" sizes="32x32" />
        <link rel="icon" href="/favicon-16x16.png" type="image/png" sizes="16x16" />
        <link rel="apple-touch-icon" href="/apple-touch-icon.png" />
        <link rel="manifest" href="/site.webmanifest" />
        
        {/* Theme Color for mobile browsers */}
        <meta name="theme-color" content={theme === "dark" ? "#0f172a" : "#ffffff"} />
      </head>
      <body className="antialiased selection:bg-indigo-500/30">
        {children}
      </body>
    </html>
  );
}
